  "inlineSchema": "// =============================================\n// QuantumGrid — Prisma Schema\n// DB: PostgreSQL (or Supabase)\n// Run: npx prisma migrate dev --name init\n// =============================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// =============================================\n// ENUMS\n// =============================================\n\nenum Role {\n  RESEARCHER\n  STUDENT\n  PROVIDER\n  INSTITUTION\n  ADMIN\n}\n\nenum InstrumentType {\n  TELESCOPE\n  QUANTUM\n  SPECTROGRAPH\n  RADIO\n  OTHER\n}\n\nenum InstrumentStatus {\n  ONLINE\n  BUSY\n  OFFLINE\n  MAINTENANCE\n}\n\nenum SessionStatus {\n  PENDING // escrow created, waiting for provider\n  ACTIVE // session running\n  COMPLETED // delivered, escrow released\n  CANCELLED // cancelled before start\n  DISPUTED // delivery contested\n  EXPIRED // escrow expired without delivery\n}\n\nenum EscrowType {\n  ESCROW // telescope: time-locked EscrowCreate\n  PAYMENT_CHANNEL // quantum: per-shot PaymentChannel\n}\n\n// =============================================\n// MODELS\n// =============================================\n\nmodel User {\n  id          String   @id @default(uuid())\n  xrplAddress String   @unique\n  email       String?  @unique\n  name        String?\n  role        Role     @default(RESEARCHER)\n  institution String?\n  avatarUrl   String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  sessions      Session[]\n  instruments   Instrument[] // if provider\n  notifications Notification[]\n\n  @@index([xrplAddress])\n  @@index([email])\n}\n\nmodel Instrument {\n  id          String           @id @default(uuid())\n  name        String\n  type        InstrumentType\n  status      InstrumentStatus @default(ONLINE)\n  location    String\n  country     String\n  latitude    Float?\n  longitude   Float?\n  priceXRP    Float // rate per unit\n  rateUnit    String // \"per_min\" | \"per_shot\" | \"per_hour\"\n  minSession  Int // minimum duration in seconds or shots\n  specs       Json // flexible: aperture, qubits, resolution, etc.\n  imageUrl    String?\n  description String?\n\n  providerId String?\n  provider   User?   @relation(fields: [providerId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sessions Session[]\n  queue    QueueEntry[]\n\n  @@index([type])\n  @@index([status])\n  @@index([providerId])\n}\n\nmodel Session {\n  id           String @id @default(uuid())\n  userId       String\n  instrumentId String\n\n  // XRPL on-chain references\n  escrowType     EscrowType\n  xrplTxHash     String? // EscrowCreate or PaymentChannelCreate tx hash\n  channelId      String? // Payment Channel ID (quantum only)\n  escrowSequence Int? // EscrowCreate sequence (telescope only)\n  conditionHex   String? // BLAKE2b condition (telescope)\n\n  // Session state\n  status      SessionStatus @default(PENDING)\n  durationSec Int // requested duration or max shots\n  actualSec   Float? // actual seconds used\n  actualShots Int? // actual shots executed (quantum)\n  xrpLocked   Float // amount locked in escrow\n  xrpSpent    Float? // actual amount consumed\n  xrpRefunded Float? // surplus returned\n\n  // Oracle data\n  oracleSessionId String? // oracle internal session id\n  receipt         Json? // signed oracle receipt\n  fulfillmentHex  String? // BLAKE2b preimage (revealed at end)\n\n  // Timestamps\n  startedAt DateTime?\n  endedAt   DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  user       User           @relation(fields: [userId], references: [id])\n  instrument Instrument     @relation(fields: [instrumentId], references: [id])\n  claims     PaymentClaim[]\n\n  @@index([userId])\n  @@index([instrumentId])\n  @@index([status])\n  @@index([xrplTxHash])\n}\n\n// Off-chain log of each Payment Channel claim (quantum per-shot)\nmodel PaymentClaim {\n  id            String   @id @default(uuid())\n  sessionId     String\n  shotNumber    Int\n  cumulativeXRP Float\n  signedClaim   String // hex signature from user wallet\n  submittedAt   DateTime @default(now())\n\n  session Session @relation(fields: [sessionId], references: [id])\n\n  @@index([sessionId])\n}\n\n// Queue for busy instruments\nmodel QueueEntry {\n  id           String   @id @default(uuid())\n  instrumentId String\n  userId       String\n  requestedSec Int\n  budgetXRP    Float\n  position     Int\n  createdAt    DateTime @default(now())\n  expiresAt    DateTime\n\n  instrument Instrument @relation(fields: [instrumentId], references: [id])\n\n  @@index([instrumentId])\n  @@index([userId])\n}\n\n// Push notifications (session updates, escrow events)\nmodel Notification {\n  id        String   @id @default(uuid())\n  userId    String\n  type      String // \"session_start\" | \"session_end\" | \"escrow_released\" | \"low_balance\"\n  title     String\n  body      String\n  read      Boolean  @default(false)\n  metadata  Json? // extra context (txHash, sessionId, etc.)\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId, read])\n}\n",
